#include <bits/stdc++.h>
#define Maxn 100
#define Maxm 100
#define Maxnum 4000000
using namespace std;
int n, m; 
int ST;
struct debug{
	int b1;
	int b2;
	int f1;
	int f2;
	int T;
} hero[Maxm + 2];
priority_queue < pair <int, int> > q;
int dis[Maxnum];
int Hash[Maxnum];
void dij () {
	memset (dis, 0x3f, sizeof (dis));
	dis[ST] = 0;
	q.push (make_pair (0, ST));
	while (q.size ()) {
		int now = q.top ().second;
		q.pop ();
		if (Hash[now] == 1) {
			continue;
		}
		Hash[now] = 1;
		for (int i = 1; i <= m; i++) {
			if ((hero[i].b1 & now) == hero[i].b1 && (hero[i].b2 & now) == 0) {
				int v = ((now | hero[i].f1) ^ hero[i].f1) | hero[i].f2;
				if (dis[now] + hero[i].T < dis[v]) {
					dis[v] = dis[now] + hero[i].T;
					q.push (make_pair (-dis[v], v));
				}
			}
		}
	}
	return ;
}
int main () {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		ST = ST | (1 << i);
	}	
	for (int i = 1; i <= m; i++) {
		cin >> hero[i].T;
		string B, F;
		cin >> B >> F;
		for (int j = 0; j < n; j++) {
			if (B[j] == '+') {
				hero[i].b1 = hero[i].b1 | (1 << (j + 1));
			}
			if (B[j] == '-') {
				hero[i].b2 = hero[i].b2 | (1 << (j + 1));
			}
			if (F[j] == '+') {
				hero[i].f2 = hero[i].f2 | (1 << (j + 1));
			}
			if (F[j] == '-') {
				hero[i].f1 = hero[i].f1 | (1 << (j + 1));
			}
		}
	}
	dij ();
	if (dis[0] == dis[Maxnum - 1]) {
		cout << 0;
	} else {
		cout << dis[0];
	}
	return 0;
}
